// ---- Helpers (parsing logic unchanged — it already works) ----
function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function toTitleCase(str) {
  return str.toLowerCase().replace(/\b\w/g, c => c.toUpperCase());
}

function slugify(label) {
  return label.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
}

function isValidUrl(url) {
  return !!url && /^https?:\/\//i.test(url);
}

function splitHeadlineSummary(block) {
  const lines = block.split('\n').map(l => l.trim()).filter(Boolean);
  if (lines.length === 0) return { headline: '', summary: '' };
  if (lines.length > 1) {
    return { headline: lines[0], summary: lines.slice(1).join(' ') };
  }
  const single = lines[0];
  const m = single.match(/^([A-Z0-9][A-Z0-9 ,'":\-]{4,}?)\s+([A-Z][a-z].*)$/);
  if (m) {
    return { headline: m[1].trim(), summary: m[2].trim() };
  }
  return { headline: single, summary: '' };
}

function parseItems(sectionBody) {
  const items = [];
  const regex = /([\s\S]*?)Link:\s*(\S+)/g;
  let match;
  while ((match = regex.exec(sectionBody)) !== null) {
    let block = match[1].replace(/^[\s=\-]+/, '').trim();
    const link = match[2].trim();
    if (!block) continue;

    let image = null;
    const imgMatch = block.match(/Image:\s*(\S+)/i);
    if (imgMatch) {
      image = isValidUrl(imgMatch[1]) ? imgMatch[1].trim() : null;
      block = block.replace(/Image:\s*\S+/i, '').trim();
    }

    const parsed = splitHeadlineSummary(block);
    if (!parsed.headline) continue;

    items.push({
      headline: parsed.headline,
      summary: parsed.summary,
      link: isValidUrl(link) ? link : null,
      image
    });
  }
  return items;
}

function extractCategories(fullText) {
  const headerRegex = /^([^\n=\-][^\n]*)\n=+[ \t]*\r?\n/gm;
  const matches = [];
  let m;
  while ((m = headerRegex.exec(fullText)) !== null) {
    matches.push({ label: m[1].trim(), contentStart: m.index + m[0].length, headerStart: m.index });
  }
  const sections = [];
  for (let i = 0; i < matches.length; i++) {
    const start = matches[i].contentStart;
    const end = i + 1 < matches.length ? matches[i + 1].headerStart : fullText.length;
    sections.push({ label: matches[i].label, body: fullText.slice(start, end).trim() });
  }
  return sections;
}

function extractOutlets(categoryBody) {
  const headerRegex = /^([^\n=\-][^\n]*)\n-+[ \t]*\r?\n/gm;
  const matches = [];
  let m;
  while ((m = headerRegex.exec(categoryBody)) !== null) {
    matches.push({ label: m[1].trim(), contentStart: m.index + m[0].length, headerStart: m.index });
  }
  const sections = [];
  for (let i = 0; i < matches.length; i++) {
    const start = matches[i].contentStart;
    const end = i + 1 < matches.length ? matches[i + 1].headerStart : categoryBody.length;
    sections.push({ label: matches[i].label, body: categoryBody.slice(start, end).trim() });
  }
  return sections;
}

// ---- Edition (category) accent system ----
// Colour is a structural device here: India = marigold, World = ink-indigo.
// Anything unrecognised falls back to the neutral ink accent.
function editionFor(label) {
  if (/india/i.test(label)) return { key: 'india', accent: '#C2570A', accentSoft: '#F4E3D2', name: toTitleCase(label) };
  if (/world/i.test(label)) return { key: 'world', accent: '#1F4B5F', accentSoft: '#DCE7EA', name: toTitleCase(label) };
  return { key: 'general', accent: '#52483B', accentSoft: '#E8E2D4', name: toTitleCase(label) };
}

// ---- Card renderers ----
function renderLead(item, ed) {
  const img = isValidUrl(item.image)
    ? `<div class="lead-media"><img src="${escapeHtml(item.image)}" alt="" loading="lazy" onerror="this.parentElement.remove();"></div>`
    : '';
  const inner = `
      ${img}
      <div class="lead-body">
        <span class="kicker" style="color:${ed.accent}">Top Story</span>
        <h2 class="lead-headline">${escapeHtml(item.headline)}</h2>
        ${item.summary ? `<p class="lead-dek">${escapeHtml(item.summary)}</p>` : ''}
        <span class="read-link" style="color:${ed.accent}">Read full story &#8594;</span>
      </div>`;
  return item.link
    ? `<a class="lead-story" href="${escapeHtml(item.link)}" target="_blank" rel="noopener">${inner}</a>`
    : `<div class="lead-story no-link">${inner}</div>`;
}

function renderStoryCard(item, ed) {
  const img = isValidUrl(item.image)
    ? `<div class="story-media"><img src="${escapeHtml(item.image)}" alt="" loading="lazy" onerror="this.parentElement.remove();"></div>`
    : '';
  const inner = `
      ${img}
      <div class="story-body">
        <h3 class="story-headline">${escapeHtml(item.headline)}</h3>
        ${item.summary ? `<p class="story-dek">${escapeHtml(item.summary)}</p>` : ''}
        <span class="read-link" style="color:${ed.accent}">Read full story &#8594;</span>
      </div>`;
  return item.link
    ? `<a class="story" href="${escapeHtml(item.link)}" target="_blank" rel="noopener">${inner}</a>`
    : `<div class="story no-link">${inner}</div>`;
}

function renderEventCard(item) {
  const img = isValidUrl(item.image)
    ? `<div class="event-media"><img src="${escapeHtml(item.image)}" alt="" loading="lazy" onerror="this.parentElement.remove();"></div>`
    : '';
  return `
    <div class="event">
      ${img}
      <div class="event-body">
        <h3>${escapeHtml(item.headline)}</h3>
        ${item.summary ? `<p>${escapeHtml(item.summary)}</p>` : ''}
        ${item.link ? `<a class="more" href="${escapeHtml(item.link)}" target="_blank" rel="noopener">Event details &#8599;</a>` : ''}
      </div>
    </div>`;
}

// ---- Main ----
const rawText = $input.first().json.text || '';
const today = new Date().toLocaleDateString('en-IN', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});
const editionStamp = new Date().toLocaleDateString('en-IN', { day: '2-digit', month: 'short' }).toUpperCase();

let parsedOk = false;
let catButtonsHtml = '';
let catPanelsHtml = '';
let eventsHtml = '';

try {
  const categories = extractCategories(rawText);

  if (categories.length > 0) {
    parsedOk = true;

    categories.forEach((cat, idx) => {
      const isEvents = /event/i.test(cat.label);

      if (isEvents) {
        const items = parseItems(cat.body);
        if (items.length === 0) {
          const emptyMsg = /no events/i.test(cat.body)
            ? 'No events scheduled this week'
            : 'No events found';
          eventsHtml = `
            <section id="events" class="events-section">
              <div class="section-head"><h2>${escapeHtml(toTitleCase(cat.label))}</h2></div>
              <p class="empty">${escapeHtml(emptyMsg)}</p>
            </section>`;
        } else {
          eventsHtml = `
            <section id="events" class="events-section">
              <div class="section-head"><h2>${escapeHtml(toTitleCase(cat.label))}</h2></div>
              <div class="event-list">${items.map(renderEventCard).join('\n')}</div>
            </section>`;
        }
        return;
      }

      // ---- Indian News / World News editions ----
      const catId = slugify(cat.label) || `cat-${idx}`;
      const ed = editionFor(cat.label);
      const outlets = extractOutlets(cat.body);

      // Build outlet -> items map, then peel off one lead story from the first outlet
      const outletData = (outlets.length > 0 ? outlets : [{ label: cat.label, body: cat.body }])
        .map(o => ({ label: o.label, items: parseItems(o.body) }))
        .filter(o => o.items.length > 0);

      let leadHtml = '';
      if (outletData.length > 0 && outletData[0].items.length > 0) {
        const lead = outletData[0].items.shift();
        leadHtml = renderLead(lead, ed);
      }

      let outletNavHtml = '';
      let outletSectionsHtml = '';
      outletData.forEach(outlet => {
        const outletId = `${catId}--${slugify(outlet.label)}`;
        outletNavHtml += `<a href="#${outletId}">${escapeHtml(toTitleCase(outlet.label))}</a>\n`;
        if (outlet.items.length === 0) return;
        outletSectionsHtml += `
          <section id="${outletId}" class="outlet-section">
            <h3 class="outlet-title" style="color:${ed.accent}">${escapeHtml(toTitleCase(outlet.label))}
              <span class="count">${outlet.items.length} ${outlet.items.length === 1 ? 'story' : 'stories'}</span>
            </h3>
            <div class="story-grid">${outlet.items.map(i => renderStoryCard(i, ed)).join('\n')}</div>
          </section>`;
      });

      if (!leadHtml && !outletSectionsHtml) {
        outletSectionsHtml = `<p class="empty">No stories available</p>`;
      }

      catButtonsHtml += `<button class="cat-btn${idx === 0 ? ' active' : ''}" data-cat="${catId}" data-accent="${ed.accent}" type="button">${escapeHtml(ed.name)}</button>\n`;
      catPanelsHtml += `
        <div class="catpanel" id="${catId}" style="display:${idx === 0 ? 'block' : 'none'}">
          ${leadHtml}
          ${outletNavHtml ? `<nav class="outlet-toc">${outletNavHtml}</nav>` : ''}
          ${outletSectionsHtml}
        </div>`;
    });
  }
} catch (e) {
  parsedOk = false;
}

if (!parsedOk) {
  const escaped = escapeHtml(rawText);
  const htmlBody = escaped
    .split(/\n\s*\n/)
    .map(p => `<p>${p.replace(/\n/g, '<br>')}</p>`)
    .join('\n');
  catPanelsHtml = `<div class="catpanel" id="raw" style="display:block">${htmlBody}</div>`;
  catButtonsHtml = '';
}

