try {
  sha = $('Get File SHA').first().json.sha;
} catch (e) {
  sha = undefined;
}

const body = {
  message: `Update daily news brief - ${new Date().toISOString()}`,
  content: content_base64,
  branch: 'main'
};

if (sha) {
  body.sha = sha;
}

return [{ json: { body } }];
